#include <bits/stdc++.h>
using namespace std;
const int N=200005;
int n,a[N],m,block,cnt[N],vis[N],ans[N];
int fun(int x)
{
	return (x-1)/block+1;
}
struct node
{
	int l,r,id;
	bool operator<(const node other) const
	{
		if(fun(l)==fun(other.l)) return r<other.r;
		return fun(l)<fun(other.l);
	}
} b[N];
void push(int x)
{
	if(vis[a[x]]==0) cnt[fun(a[x])]++;
	vis[a[x]]++;
}
void pop(int x)
{
	vis[a[x]]--;
	if(vis[a[x]]==0) cnt[fun(a[x])]--;
}
int query()
{
	for(int i=1;;i++)
	{
		if(cnt[i]==block) continue;
		for(int j=(i-1)*block+1;;j++)
		{
			if(vis[j]==0) return j-1;
		}
	}
}
int main()
{
//	freopen("P4137_1.in","r",stdin);
//	freopen("P4137_1(my).out","w",stdout);
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n>>m;
	block=sqrt(n);
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
		a[i]++;
	}
	for(int i=1;i<=m;i++)
	{
		int l,r;
		cin>>l>>r;
		b[i]=node{l,r,i};
	}
	sort(b+1,b+1+m);
	int l=1,r=0;
	for(int i=1;i<=m;i++)
	{
		int ll=b[i].l,rr=b[i].r;
		while(r<rr)
		{
			push(++r);
		}
		while(r>rr)
		{
			pop(r--);
		}
		while(l<ll)
		{
			pop(l++);
		}
		while(l>ll)
		{
			push(--l);
		}
		ans[b[i].id]=query();
	}
	for(int i=1;i<=m;i++) cout<<ans[i]<<"\n";
	return 0;
}
